class Solution {
public:
    Solution(vector<int>& w) : prefixSum(w) {
        for (int i = 1; i < w.size(); ++i) {
            prefixSum[i] += prefixSum[i - 1];
        }
        total = prefixSum.back();
    }

    int pickIndex() {
        int target = rand() % total + 1;
        int left = 0, right = prefixSum.size() - 1;
        while (left < right) {
            int mid = left + (right - left) / 2;
            if (prefixSum[mid] < target) {
                left = mid + 1;
            } else {
                right = mid;
            }
        }
        return left;
    }
private:
    vector<int> prefixSum;
    int total;
};
